#include <stdio.h>
#include <stdlib.h>
#define INF 1000000000
#define MAX_V 100000
#define MAX_E 100000

typedef struct Edge {
    int u, v, w;
} Edge;

int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->w - e2->w;
}

int find(int *parent, int i) {
    if (parent[i] == i) return i;
    return find(parent, parent[i]);
}

void unionSet(int *parent, int *rank, int u, int v) {
    int x = find(parent, u);
    int y = find(parent, v);
    if (x != y) {
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else if (rank[x] > rank[y]) {
            parent[y] = x;
        } else {
            parent[y] = x;
            rank[x]++;
        }
    }
}

int kruskal(Edge *edges, int V, int E) {
    int *parent = (int *)malloc(V * sizeof(int));
    int *rank = (int *)malloc(V * sizeof(int));
    for (int i = 0; i < V; i++) {
        parent[i] = i;
        rank[i] = 0;
    }
    qsort(edges, E, sizeof(Edge), compare);
    int sum = 0;
    for (int i = 0; i < E; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int w = edges[i].w;
        if (find(parent, u) != find(parent, v)) {
            unionSet(parent, rank, u, v);
            sum += w;
        }
    }
    free(parent);
    free(rank);
    return sum;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Edge *edges = (Edge *)malloc(E * sizeof(Edge));
    for (int i = 0; i < E; i++) {
        scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);
    }
    int sum = kruskal(edges, V, E);
    printf("%d\n", sum);
    free(edges);
    return 0;
}

